import api from './app/client';
import type { LeaveBalanceDTO, LeaveBalanceCreateDTO, Guid } from './leaveService';

export type { LeaveBalanceDTO };

export const leaveBalanceService = {
  getLedger: (userProfileId: string): Promise<LeaveBalanceDTO[]> =>
    api.get(`/leave-balance/${userProfileId}`).then(r => r.data),

  getLedgerByFinancialYear: (userProfileId: string, financialYear: string): Promise<LeaveBalanceDTO[]> =>
    api.get(`/leave-balance/${userProfileId}/financial-year/${financialYear}`).then(r => r.data),

  listByUser: (userProfileId: Guid): Promise<LeaveBalanceDTO[]> =>
    api.get(`/leave-balance/${userProfileId}`).then(r => r.data),

  listByFinancialYear: (userProfileId: Guid, financialYear: string): Promise<LeaveBalanceDTO[]> =>
    api.get(`/leave-balance/${userProfileId}/financial-year/${financialYear}`).then(r => r.data),

  create: (data: LeaveBalanceCreateDTO): Promise<LeaveBalanceDTO> =>
    api.post('/leave-balance', data).then(r => r.data),

  generateAccrual: (userProfileId: Guid, year: number, month: number): Promise<LeaveBalanceDTO> =>
    api.post(`/leave-balance/${userProfileId}/accrual/${year}/${month}`).then(r => r.data),

  remove: (id: Guid) =>
    api.delete(`/leave-balance/${id}`).then(r => r.data),
};
